(window.webpackJsonp=window.webpackJsonp||[]).push([[262],{889:function(n,a){n.exports='\x3c!-- \ntitle: 05-SqlMap\nsort: \n--\x3e \n\n## 基础使用\n\n- 查询数据库\n\n> `-Raw`: 文件\n>\n> `-Parameter`: 参数\n>\n> `--dbs`: 全部数据库\n>\n> `sqlmap -r xxx -p pwd --dbs`\n\n- 使用url\n\n> `-Url`: 网址\n>\n> `sqlmap -u http://xxx -p pwd --dbs`\n\n- 详细信息\n\n> `-Database`: 数据库名称\n>\n> `-Table`: 数据表名称\n>\n> `-Columns`: 行名称\n>\n> 指定数据库下的数据表\n>\n> `sqlmap -r xxx -p id -D dvwa --tables`\n>\n> 表中的全部列\n>\n> `sqlmap -r xxx -p id -D dvwa -T users --columns`\n>\n> 表中的具体字段\n>\n> `sqlmap -r xxx -p id -D dvwa -T users -C user_id,avatar,password --dump`\n\n- 直连\n\n> `--users`: 用户信息\n>\n> `sqlmap -d "musql://root:1234@127.0.0.1:3306/dbname" -f --banner`\n\n## 设置\n\n- 请求方法\n\n> `--data="id=1"`\n>\n> `--method=POST`'}}]);